from django.core.management.base import BaseCommand
from django.utils import timezone
from datetime import timedelta
from reservations.models import Reserva
from reservations.services.email import enviar_recordatorio_pago


class Command(BaseCommand):
    help = 'Envía recordatorios de pago pendiente a clientes'

    def handle(self, *args, **options):
        manana = timezone.now().date() + timedelta(days=1)
        reservas_pendientes = Reserva.objects.filter(
            estado='PENDIENTE_DE_PAGO',
            fecha_inicio=manana
        )

        for reserva in reservas_pendientes:
            enviar_recordatorio_pago(reserva)
            self.stdout.write(
                self.style.SUCCESS(
                    f'Recordatorio enviado para reserva {reserva.codigo_seguimiento}'
                )
            )
